const crypto = require('crypto');
// Use rawBody (the original request bytes) for HMAC computation, NOT JSON.stringify of the parsed object.
// The webhook trigger must have 'Raw Body' option enabled.
const rawBody = $input.first().json.rawBody || '';
const secret = process.env.TYPEFORM_WEBHOOK_SECRET || '';
const signature = ($input.first().json.headers && $input.first().json.headers['typeform-signature']) ? $input.first().json.headers['typeform-signature'] : '';
const expectedSig = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
const isValid = secret.length > 0 && rawBody.length > 0 && signature === expectedSig;
if (!isValid) {
  throw new Error('Unauthorized: Invalid or missing Typeform webhook signature');
}
// Parse the raw body for downstream use
const parsedBody = JSON.parse(rawBody);
return [{ json: { body: parsedBody, headers: $input.first().json.headers } }];

const body = $input.first().json.body;
const answers = (body.form_response && body.form_response.answers) ? body.form_response.answers : [];
const findAnswer = (ref) => answers.find(a => a.field && a.field.ref === ref);
const email = (findAnswer('email_field')?.email ?? '').toLowerCase().trim();
const first_name = findAnswer('first_name_field')?.text ?? '';
const last_name = findAnswer('last_name_field')?.text ?? '';
const phone = findAnswer('phone_field')?.phone_number ?? '';
const company = findAnswer('company_field')?.text ?? '';
const submitted_at = body.form_response?.submitted_at ?? '';
const form_response_token = body.form_response?.token ?? '';
return [{ json: { email, first_name, last_name, phone, company, submitted_at, form_response_token } }];

const item = $input.first().json;
const email = item.email || '';
const firstName = item.first_name || '';
const lastName = item.last_name || '';
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValid = email.length > 0 && emailRegex.test(email) && firstName.length > 0 && lastName.length > 0;
return [{ json: { ...item, fields_valid: isValid, validation_error: isValid ? '' : 'Missing or invalid required fields (email, first_name, last_name)' } }];

const formData = $('Validate Required Fields').first().json;
const crmResponse = $input.first().json;
// Defensively handle multiple CRM response shapes
let contacts = [];
if (Array.isArray(crmResponse.contacts)) {
  contacts = crmResponse.contacts;
} else if (Array.isArray(crmResponse.data)) {
  contacts = crmResponse.data;
} else if (Array.isArray(crmResponse)) {
  contacts = crmResponse;
}
const isExisting = contacts.length > 0;
const existingId = isExisting ? contacts[0].id : null;
return [{
  json: {
    email: formData.email,
    first_name: formData.first_name,
    last_name: formData.last_name,
    phone: formData.phone,
    company: formData.company,
    submitted_at: formData.submitted_at,
    form_response_token: formData.form_response_token,
    is_existing_contact: isExisting,
    existing_contact_id: existingId
  }
}];
